import SwiftUI

struct ArtistDetailView: View { let artist: Artist; var body: some View { ScrollView { VStack(alignment: .leading, spacing: 16) { RemoteArtworkView(url: artist.imageURL, size: 220); Text(artist.name).font(.largeTitle.bold()).foregroundStyle(.white); Button("Follow") {}.thereButtonStyle(); Text("Top Tracks").font(.title2.bold()).foregroundStyle(.white); ForEach(artist.topTracks) { TrackRowView(track: $0) {} } }.padding() }.background(Color.black.ignoresSafeArea()) } }
struct AlbumDetailView: View { let album: Album; var body: some View { ScrollView { VStack(alignment: .leading, spacing: 16) { RemoteArtworkView(url: album.artworkURL, size: 220); Text(album.title).font(.largeTitle.bold()).foregroundStyle(.white); Text("\(album.artistName) • \(album.releaseYear)").foregroundStyle(ColorPalette.textSecondary); Button("Add to Library") {}.thereButtonStyle(); ForEach(album.tracks) { TrackRowView(track: $0) {} } }.padding() }.background(Color.black.ignoresSafeArea()) } }
struct PlaylistDetailView: View { let playlist: Playlist; var body: some View { AlbumDetailView(album: Album(id: playlist.id, title: playlist.title, artistName: playlist.subtitle, artworkURL: playlist.artworkURL, releaseYear: "2026", tracks: playlist.tracks)) } }
struct TrackDetailsView: View { let track: Track; var body: some View { VStack { RemoteArtworkView(url: track.artworkURL, size: 220); Text(track.title).font(.title.bold()); Text(track.artistName); Text(track.albumTitle) }.foregroundStyle(.white).background(Color.black) } }
